async function getWhatsappSettingsWithFallback(userId: string) {
  const settings = await storage.getWhatsappSettingsByUserId(userId);
  return settings || null;
}

function getActiveAccountToken(settings: any): { accessToken: string; wabaId: string; phoneNumberId: string } {
  const accounts = (settings?.accounts as Array<{ label: string; phoneNumberId: string; wabaId: string; accessToken?: string }>) || [];
  const activePhoneId = settings?.phoneNumberId || "";
  const activeAccount = accounts.find(a => a.phoneNumberId === activePhoneId);
  
  let accessToken: string;
  let tokenSource: string;
  if (activeAccount?.accessToken) {
    accessToken = activeAccount.accessToken.trim();
    tokenSource = 'per-account';
  } else {
    accessToken = (settings?.accessToken || "").trim();
    tokenSource = 'main-settings';
  }
  
  const wabaId = (activeAccount?.wabaId || settings?.wabaId || "").trim();
  const phoneNumberId = (activeAccount?.phoneNumberId || settings?.phoneNumberId || "").trim();
  
  console.log(`📱 WhatsApp token resolution: phone=${phoneNumberId}, waba=${wabaId}, tokenSource=${tokenSource}, tokenLen=${accessToken.length}`);
  
  return { accessToken, wabaId, phoneNumberId };
}

// Startup: ensure all WhatsApp accounts have per-account tokens
// Only shares tokens between accounts on the SAME WABA within the SAME user
setTimeout(async () => {
  try {
    const rows = await db.execute(sql`SELECT user_id, accounts, access_token FROM whatsapp_settings WHERE accounts IS NOT NULL`);
    for (const row of rows.rows) {
      const accounts = row.accounts as any[];
      if (!accounts || !Array.isArray(accounts)) continue;
      
      // Build a map of WABA -> best available token from sibling accounts (same user only)
      const wabaTokenMap: Record<string, string> = {};
      for (const acc of accounts) {
        if (acc.accessToken && acc.accessToken.length >= 100 && acc.wabaId) {
          if (!wabaTokenMap[acc.wabaId] || acc.accessToken.length > wabaTokenMap[acc.wabaId].length) {
            wabaTokenMap[acc.wabaId] = acc.accessToken;
          }
        }
      }
      
      let changed = false;
      for (const acc of accounts) {
        if (!acc.accessToken || acc.accessToken.length < 100) {
          // Only use a token from a sibling account on the same WABA (same user)
          if (acc.wabaId && wabaTokenMap[acc.wabaId]) {
            acc.accessToken = wabaTokenMap[acc.wabaId];
            changed = true;
            console.log(`📱 WhatsApp: Backfilled token for "${acc.label}" from same-WABA sibling (user ${row.user_id}), len=${acc.accessToken.length}`);
          }
        }
      }
      
      if (changed) {
        await db.execute(sql`UPDATE whatsapp_settings SET accounts = ${JSON.stringify(accounts)}::jsonb WHERE user_id = ${row.user_id}`);
      }
    }
  } catch (err) {
    console.warn("WhatsApp token backfill skipped:", err);
  }
}, 2000);

async function getAllUserIds(userId: number | string): Promise<string[]> {
  const ids = new Set<string>([String(userId)]);
  try {
    let isAdmin = false;
    
    const pubRows = await db.execute(
      sql`SELECT id, email, role FROM public_users WHERE id = ${Number(userId) || 0} OR id::text = ${String(userId)} LIMIT 1`
    );
    for (const r of pubRows.rows) {
      ids.add(String((r as any).id));
      if ((r as any).role === "admin") isAdmin = true;
    }

    const userRows = await db.execute(
      sql`SELECT id, email, role FROM users WHERE id = ${String(userId)} LIMIT 1`
    );
    for (const r of userRows.rows) {
      ids.add(String((r as any).id));
      if ((r as any).role === "admin") isAdmin = true;
    }

    if (isAdmin) {
      const allUsers = await db.execute(sql`SELECT id FROM users`);
      for (const r of allUsers.rows) ids.add(String((r as any).id));
      const allPub = await db.execute(sql`SELECT id FROM public_users`);
      for (const r of allPub.rows) ids.add(String((r as any).id));
    } else {
      const emails = new Set<string>();
      for (const r of [...pubRows.rows, ...userRows.rows]) {
        if ((r as any).email) emails.add((r as any).email);
      }
      for (const email of emails) {
        const moreUsers = await db.execute(sql`SELECT id FROM users WHERE email = ${email}`);
        for (const r of moreUsers.rows) ids.add(String((r as any).id));
        const morePub = await db.execute(sql`SELECT id FROM public_users WHERE email = ${email}`);
        for (const r of morePub.rows) ids.add(String((r as any).id));
      }
    }
  } catch (e) {
    console.error("getAllUserIds error:", e);
  }
  return Array.from(ids);
}

