  app.post("/api/scheduled-posts/generate-weekly", async (req, res) => {
    try {
      const user = await storage.getUserByUsername("mikebjork");
      if (!user) {
        return res.status(404).json({ error: "User not found" });
      }

      const { focus = "mixed" } = req.body; // 'local_markets', 'moving_guide', or 'mixed'

      const neighborhoods = [
        "Dundee",
        "Aksarben",
        "Old Market",
        "Blackstone",
        "Benson",
      ];

      // Research-backed posting frequency: 0=Sun,1=Mon,2=Tue,3=Wed,4=Thu,5=Fri,6=Sat
      const platformPostingDays: Record<string, number[]> = {
        facebook:  [0, 1, 2, 3, 4, 5, 6],
        instagram: [1, 3, 5, 6],
        linkedin:  [1, 3, 5],
        x:         [1, 2, 3, 4, 5],
        tiktok:    [1, 2, 4, 6],
      };

      const movingGuideTopics = [
        "Best Omaha neighborhoods for families",
        "Omaha job market and major employers",
        "Winter in Omaha: what to expect",
        "Omaha school districts comparison",
        "Cost of living in Omaha vs other cities",
      ];

      const today = new Date();
      const generatedPosts = [];

      // Generate 2 weeks of content, one post per scheduled platform per day
      for (let day = 0; day < 14; day++) {
        const scheduleDate = new Date(today);
        scheduleDate.setDate(today.getDate() + day + 1);
        const dayOfWeek = scheduleDate.getDay();

        // Only post to platforms scheduled for this day of week
        const scheduledPlatforms = Object.entries(platformPostingDays)
          .filter(([, days]) => days.includes(dayOfWeek))
          .map(([p]) => p);

        if (scheduledPlatforms.length === 0) continue;

        // Pick one platform per day (cycle through scheduled ones)
        const platform = scheduledPlatforms[day % scheduledPlatforms.length];
        scheduleDate.setHours(9 + (day % 8), 0, 0, 0);

        let aiContent, postType, neighborhood;

        try {
          if (
            focus === "local_markets" ||
            (focus === "mixed" && day % 2 === 0)
          ) {
            // Generate local market content
            const neighborhoodIndex = day % neighborhoods.length;
            neighborhood = neighborhoods[neighborhoodIndex];
            // Use existing content generation for now
            aiContent = await openaiService.generateContent({
              type: "social",
              neighborhood,
              keywords: [`${neighborhood} real estate`, "Omaha homes"],
            });
            postType = "local_market";
          } else {
            // Generate moving guide content
            const topicIndex = day % movingGuideTopics.length;
            const topic = movingGuideTopics[topicIndex];
            // Use existing content generation for now
            aiContent = await openaiService.generateContent({
              type: "social",
              neighborhood: topic,
              keywords: ["Omaha moving", "real estate tips"],
            });
            postType = "moving_guide";
            neighborhood = null;
          }

          const scheduledPost = await storage.createScheduledPost({
            userId: user.id,
            platform,
            postType,
            content: aiContent.content,
            hashtags: (aiContent as any).hashtags || [],
            scheduledFor: scheduleDate,
            status: "pending",
            isEdited: false,
            isAiGenerated: true,
            originalContent: aiContent.content,
            neighborhood,
            seoScore: aiContent.seoScore || 80,
            metadata: { generated: true, focus: postType, aiGenerated: true, businessType: (companyProfile as any)?.businessType || "real_estate" },
          });

          generatedPosts.push(scheduledPost);
        } catch (aiError) {
          console.error(
            `Failed to generate AI content for day ${day}:`,
            aiError
          );
          // Fallback to basic content if AI generation fails
          const fallbackContent = neighborhood
            ? `Discover what makes ${neighborhood} special! Contact Mike Bjork for local market insights.`
            : `Thinking of moving to Omaha? Let's talk about what makes this city amazing!`;

          const scheduledPost = await storage.createScheduledPost({
            userId: user.id,
            platform,
            postType: postType || "local_market",
            content: fallbackContent,
            hashtags: ["OmahaRealEstate", "MovingToOmaha", "NebraskaHomes"],
            scheduledFor: scheduleDate,
            status: "pending",
            isEdited: false,
            isAiGenerated: false,
            seoScore: 85,
            originalContent: fallbackContent,
            neighborhood,
            metadata: { generated: true, focus: postType, fallback: true, businessType: (companyProfile as any)?.businessType || "real_estate" },
          });

          generatedPosts.push(scheduledPost);
        }
      }

      res.json({
        success: true,
        message: `Weekly ${focus} content generated successfully with AI optimization`,
        postsGenerated: generatedPosts.length,
        focus: focus,
      });
    } catch (error) {
      console.error("Generate weekly content error:", error);
      res.status(500).json({ error: "Failed to generate weekly content" });
    }
  });

  // Fix blank/empty scheduled posts using instant fallback templates (no AI calls)
  app.post("/api/scheduled-posts/fix-blank", requireAuth, async (req: any, res) => {
    try {
      const user = (req as any).user;
      if (!user?.id) return res.status(401).json({ error: "User not authenticated" });
      const userId = String(user.id);

      const allPosts = await storage.getScheduledPosts(userId);
      const blankPosts = allPosts.filter((p: any) => !p.content || !p.content.trim());

      if (blankPosts.length === 0) {
        return res.json({ fixed: 0, message: "No blank posts found" });
      }

      const companyProfile = await storage.getCompanyProfile(userId);
      const businessType = (companyProfile as any)?.businessType || "real_estate";
      const agentName = (companyProfile as any)?.agentName || (companyProfile as any)?.contactName || "";
      const businessName = (companyProfile as any)?.businessName || (companyProfile as any)?.brokerageName || "";
      const city = (companyProfile as any)?.city || "your area";

      const getTemplate = (category: string, neighborhood: string, platform: string): string => {
        const loc = neighborhood || city;
        const byline = agentName ? `— ${agentName}${businessName ? ` | ${businessName}` : ""}` : (businessName ? `— ${businessName}` : "");
        const cta = agentName ? `Contact ${agentName} today!` : "Contact us today!";
        const bType = businessType.replace(/_/g, " ");

        if (businessType !== "real_estate") {
          const restaurantTemplates: Record<string, string> = {
            menu_highlight: `🍽️ Have you tried our latest menu creation? Made with the freshest local ingredients and bursting with flavor. Come in and taste the difference ${byline}. #MenuHighlight #FoodLovers #EatLocal`,
            daily_special: `⭐ TODAY'S SPECIAL is here and it won't last long! Fresh, delicious, and made with love. Come in early to grab yours ${byline}. #DailySpecial #FoodOfTheDay #Foodie`,
            behind_the_scenes: `👨‍🍳 Every great dish starts behind the scenes — our team is up before sunrise preparing the freshest ingredients just for you. Thank you for your support ${byline}! #BehindTheScenes #FreshFood #OurTeam`,
            customer_spotlight: `⭐ Nothing makes us happier than seeing our guests smile! Thank you to all our loyal customers — you're the reason we do what we do ${byline}. #CustomerLove #Grateful #Community`,
            weekend_promo: `🎉 Weekend vibes are calling! Join us for great food, great company, and an unforgettable experience. Special weekend deals available — see you there ${byline}! #WeekendSpecial #FoodAndFun #DineOut`,
            new_item: `🆕 Something NEW just hit our menu and we think you're going to love it! Stop by and be among the first to try it ${byline}. #NewMenuItem #MustTry #Foodie`,
            event_promotion: `📅 We've got something special coming up! Mark your calendar and join us for a great time ${byline}. #SpecialEvent #CommunityLove #DineWithUs`,
          };
          return restaurantTemplates[category]
            || `✨ Great things happening at ${businessName || "our place"}! Check out our ${category.replace(/_/g, " ")} — ${cta} #${bType.replace(/\s/g, "")} #Local`;
        }

        const reTemplates: Record<string, string[]> = {
          market_update: [
            `📊 ${loc} Real Estate Market Update: Inventory is shifting and prices are moving. Whether you're buying or selling, now is the time to make your move. ${cta} ${byline} #RealEstate #MarketUpdate #${loc.replace(/\s/g, "")}`,
          ],
          buyer_tips: [
            `🏡 Buyer Tip: The #1 thing to do before house hunting? Get pre-approved! It shows sellers you're serious and helps you move fast in a competitive market ${byline}. ${cta} #HomeBuying #BuyerTips #FirstTimeHomebuyer`,
          ],
          seller_tips: [
            `💡 Seller Tip: Homes that are staged sell faster AND for more money. Declutter, fresh paint, and curb appeal can add thousands to your sale price ${byline}. ${cta} #SellerTips #HomeStaging #ListingTips`,
          ],
          neighborhood_spotlight: [
            `✨ Spotlight on ${loc}! Top-rated schools, walkable dining, and a community that truly feels like home. Want to see what's available here? ${byline} ${cta} #NeighborhoodSpotlight #${loc.replace(/\s/g, "")} #RealEstate`,
          ],
          home_improvement: [
            `🔨 Top 3 home upgrades with the best ROI: 1️⃣ Kitchen refresh 2️⃣ Bathroom update 3️⃣ Landscaping. Small investments that make a BIG difference at sale time ${byline}. #HomeImprovement #DIY #HomeValue`,
          ],
          investment_tips: [
            `📈 Real estate in ${loc} continues to be one of the strongest investment opportunities available. Rental income + appreciation = long-term wealth ${byline}. ${cta} #RealEstateInvesting #PassiveIncome`,
          ],
          community_events: [
            `🎉 Love where you live! ${loc} has so much going on — farmers markets, community festivals, local sports, and more. This is what makes a house a HOME ${byline}. #CommunityLove #${loc.replace(/\s/g, "")}`,
          ],
          success_stories: [
            `🎊 Another family found their dream home in ${loc}! Watching clients get the keys to their forever home never gets old. Ready to write YOUR story? ${byline} ${cta} #JustClosed #HappyClients #DreamHome`,
          ],
          open_houses: [
            `🏠 Open House This Weekend in ${loc}! Gorgeous finishes, functional layout, and a neighborhood you'll fall in love with ${byline}. ${cta} #OpenHouse #HomeTour #${loc.replace(/\s/g, "")}`,
          ],
          just_listed: [
            `🆕 Just Listed in ${loc}! This stunning property just hit the market and it won't last long. DM me for a private showing ${byline}. ${cta} #JustListed #NewListing #${loc.replace(/\s/g, "")}RealEstate`,
          ],
        };

        const options = reTemplates[category] || [
          `🏡 Looking to buy or sell in ${loc}? The market is active and opportunities are available right now ${byline}. ${cta} #RealEstate #${loc.replace(/\s/g, "")}`,
        ];
        return options[0];
      };

      // Update all blank posts in parallel using templates (instant, no AI calls)
      const updates = blankPosts.map((post: any) => {
        const category = post.postType || "market_update";
        const neighborhood = post.neighborhood || city;
        const content = getTemplate(category, neighborhood, post.platform);
        return storage.updateScheduledPost(post.id, {
          content,
          isAiGenerated: false,
          originalContent: content,
        } as any).catch((err: any) => {
          console.error(`Failed to update post ${post.id}:`, err);
          return null;
        });
      });

      const results = await Promise.all(updates);
      const fixed = results.filter((r: any) => r !== null).length;

      res.json({ fixed, total: blankPosts.length });
    } catch (error) {
      console.error("Fix blank posts error:", error);
      res.status(500).json({ error: "Failed to fix blank posts" });
    }
  });

  app.post("/api/scheduled-posts/generate-monthly", requireAuth, async (req: any, res) => {
    try {
      const user = (req as any).user;
      if (!user?.id) {
        return res.status(401).json({ error: "User not authenticated" });
      }
      const userId = String(user.id);

      const {
        platforms = ["facebook", "instagram", "linkedin", "x"],
        postsPerWeek = 3,
        month,
        year,
        weeks: requestedWeeks,
        categories: userCategories,
        agentName,
        startDay: requestedStartDay,
      } = req.body;

      if (month === undefined || year === undefined) {
        return res.status(400).json({ error: "month and year are required" });
      }

      const now = new Date();
      const todayStart = new Date(now.getFullYear(), now.getMonth(), now.getDate());
      const isCurrentMonth = month === now.getMonth() && year === now.getFullYear();
      const isPastMonth = year < now.getFullYear() || (year === now.getFullYear() && month < now.getMonth());
      if (isPastMonth) {
        return res.status(400).json({ error: "Cannot generate posts for past months" });
      }
      const maxDay = new Date(year, month + 1, 0).getDate();
      const parsedStartDay = typeof requestedStartDay === 'number' && Number.isFinite(requestedStartDay) ? Math.round(requestedStartDay) : null;
      let effectiveStartDay = parsedStartDay
        ? Math.max(1, Math.min(parsedStartDay, maxDay))
        : isCurrentMonth ? now.getDate() : 1;
      if (isCurrentMonth && effectiveStartDay < now.getDate()) {
        effectiveStartDay = now.getDate();
      }

      const clampedPostsPerWeek = Math.min(Math.max(1, postsPerWeek), 7);
      const isTwoWeekMode = requestedWeeks === 2;

      const companyProfile = await storage.getCompanyProfile(userId);
      const businessType = (companyProfile as any)?.businessType || 'real_estate';

      const { INDUSTRY_CALENDAR_BLUEPRINTS: blueprints } = await import("@shared/industryCalendarBlueprints");
      const { INDUSTRY_CONTENT: industryContentMap } = await import("@shared/industryContent");
      const blueprint = blueprints[businessType];
      const industryContent = industryContentMap[businessType] || industryContentMap.general;

      const realEstateCategories = [
        "market_update", "buyer_tips", "seller_tips", "neighborhood_spotlight",
        "home_improvement", "investment_tips", "community_events", "success_stories",
        "open_houses", "just_listed",
      ];
      const defaultCategories = (blueprint && businessType !== 'real_estate')
        ? blueprint.postTypes
        : realEstateCategories;

      const categories =
        userCategories && userCategories.length > 0
          ? userCategories
          : defaultCategories;

      const marketData = await storage.getMarketData(userId);
      const serviceAreaNames = marketData.map(m => m.neighborhood).filter(Boolean) as string[];
      const compCity = (companyProfile as any)?.city || '';

      const defaultOmahaNeighborhoods = [
        "Dundee", "Aksarben", "Old Market", "Blackstone", "Benson",
        "Midtown", "West Omaha", "Elkhorn", "Papillion", "Bellevue",
      ];

      const neighborhoods = serviceAreaNames.length > 0
        ? serviceAreaNames
        : compCity
          ? [compCity, `North ${compCity}`, `South ${compCity}`, `East ${compCity}`, `West ${compCity}`, `Downtown ${compCity}`]
          : defaultOmahaNeighborhoods;

      const postingHours = [9, 11, 13, 15, 17];

      const firstDay = new Date(year, month, effectiveStartDay);
      const lastDay = new Date(year, month + 1, 0);
      const fullMonthDays = lastDay.getDate();
      const remainingDays = fullMonthDays - effectiveStartDay + 1;
      const daysInMonth = isTwoWeekMode ? Math.min(14, remainingDays) : remainingDays;
      const totalWeeks = isTwoWeekMode ? 2 : Math.ceil(remainingDays / 7);

      const realEstateCategoryKeywords: Record<string, string[]> = {
        market_update: ["market trends", "home prices", "real estate market"],
        buyer_tips: ["home buying tips", "first time buyer", "mortgage advice"],
        seller_tips: ["home selling", "listing tips", "staging advice"],
        neighborhood_spotlight: ["neighborhood guide", "community living", "local amenities"],
        home_improvement: ["home renovation", "property value", "home upgrades"],
        investment_tips: ["real estate investment", "rental property", "ROI"],
        community_events: ["local events", "community activities", "neighborhood fun"],
        success_stories: ["client testimonial", "home sold", "happy homeowners"],
        open_houses: ["open house", "home tour", "property viewing"],
        just_listed: ["new listing", "homes for sale", "just listed"],
      };

      const industryKeywords: Record<string, string[]> = {};
      if (blueprint && businessType !== 'real_estate') {
        for (const postType of blueprint.postTypes) {
          industryKeywords[postType] = [
            postType.replace(/_/g, ' '),
            ...industryContent.hashtags.slice(0, 3).map((h: string) => h.replace('#', '')),
          ];
        }
      }

      const categoryKeywordsMap = (blueprint && businessType !== 'real_estate')
        ? industryKeywords
        : realEstateCategoryKeywords;

      const generatedPosts: any[] = [];
      const delay = (ms: number) => new Promise((resolve) => setTimeout(resolve, ms));
      let postCounter = 0;

      const dayNameToOffset: Record<string, number> = {
        Sunday: 0, Monday: 1, Tuesday: 2, Wednesday: 3,
        Thursday: 4, Friday: 5, Saturday: 6,
      };

      const generatePost = async (
        scheduleDate: Date,
        category: string,
        neighborhood: string,
        platform: string,
        blueprintDescription?: string,
      ) => {
        if (scheduleDate < todayStart) return;
        let content = "";
        let hashtags: string[] = [];
        let seoScore = 80;
        let isAiGenerated = true;

        const businessLabel = businessType.replace(/_/g, ' ');
        const topicLabel = blueprintDescription
          ? blueprintDescription
          : category.replace(/_/g, ' ').replace(/\b\w/g, (c: string) => c.toUpperCase());

        try {
          if (postCounter > 0) await delay(500);

          const aiResult = await openaiService.generateSocialMediaPost(
            topicLabel,
            platform,
            neighborhood,
            { ...(agentName ? { agentName } : {}), businessType } as any,
            businessType,
          );
          content = (aiResult.content || "").trim();
          hashtags = aiResult.hashtags || [];
          seoScore = 80;
        } catch (aiError) {
          console.error(`Failed to generate AI content for post ${postCounter + 1}:`, aiError);
          isAiGenerated = false;
        }

        // Final safety: if AI returned nothing, use hardcoded fallback templates
        if (!content) {
          isAiGenerated = false;
          const genericFallback = `Discover what makes ${neighborhood} special! Contact ${agentName || "us"} for ${businessLabel} insights.`;

          const realEstateFallbackTemplates: Record<string, string> = {
            market_update: `📊 ${neighborhood} Market Update: The real estate market is showing exciting trends! Contact ${agentName || "your agent"} for the latest insights on homes in ${neighborhood}.`,
            buyer_tips: `🏡 Buyer Tip: Looking to buy in ${neighborhood}? Here are key things to consider when house hunting in this neighborhood!`,
            seller_tips: `💡 Seller Tip: Thinking of selling your ${neighborhood} home? Proper staging and pricing can make all the difference. Let's chat!`,
            neighborhood_spotlight: `✨ Neighborhood Spotlight: ${neighborhood} offers incredible community charm, great schools, and beautiful homes. Discover why residents love it!`,
            home_improvement: `🔨 Home Improvement: Simple upgrades that boost your ${neighborhood} home's value. Small changes, big returns!`,
            investment_tips: `📈 Investment Insight: ${neighborhood} continues to be a smart real estate investment. Let me show you the numbers!`,
            community_events: `🎉 Community Events: Exciting things happening in ${neighborhood}! Stay connected with your neighbors and local activities.`,
            success_stories: `🎊 Another happy homeowner in ${neighborhood}! It's always rewarding to help families find their perfect home.`,
            open_houses: `🏠 Open House Alert: Don't miss this beautiful home in ${neighborhood}! Schedule your visit today.`,
            just_listed: `🆕 Just Listed in ${neighborhood}! A stunning property has hit the market. Contact ${agentName || "us"} for details before it's gone!`,
          };

          const industryFallbackTemplates: Record<string, string> = {};
          if (blueprint && businessType !== 'real_estate') {
            for (const pt of blueprint.postTypes) {
              industryFallbackTemplates[pt] = `${pt.replace(/_/g, ' ').replace(/\b\w/g, c => c.toUpperCase())} — ${neighborhood} area. ${agentName || 'We'} bring the best ${businessLabel} service to your community. Contact us today!`;
            }
          }

          const fallbackTemplates = (businessType !== 'real_estate' && Object.keys(industryFallbackTemplates).length > 0)
            ? industryFallbackTemplates
            : realEstateFallbackTemplates;

          content = fallbackTemplates[category] || genericFallback;
          const fallbackHashtags = industryContent.hashtags.slice(0, 3).map((h: string) => h.replace('#', ''));
          hashtags = [...fallbackHashtags, neighborhood.replace(/\s/g, ""), category.replace(/_/g, "")];
          seoScore = 70;
        }

        const scheduledPost = await storage.createScheduledPost({
          userId,
          platform,
          postType: category,
          content,
          hashtags,
          scheduledFor: scheduleDate,
          status: "pending",
          isEdited: false,
          isAiGenerated,
          originalContent: content,
          neighborhood,
          seoScore,
          metadata: { generated: true, monthlyPlan: true, category, aiGenerated: isAiGenerated, blueprintDriven: isTwoWeekMode, businessType },
        });
        generatedPosts.push(scheduledPost);
        postCounter++;
      };

      const realEstateBlueprint = {
        week1: [
          { day: "Monday", contentType: "market_update", description: "Share local market stats, median prices, and inventory trends for your area", platforms: ["facebook", "linkedin", "x"] },
          { day: "Wednesday", contentType: "buyer_tips", description: "First-time buyer advice or mortgage tips with a clear call to action", platforms: ["instagram", "facebook"] },
          { day: "Friday", contentType: "just_listed", description: "Showcase a new listing with professional photos and key features", platforms: ["instagram", "facebook", "x"] },
        ],
        week2: [
          { day: "Tuesday", contentType: "neighborhood_spotlight", description: "Highlight a local neighborhood with schools, dining, and lifestyle perks", platforms: ["instagram", "facebook"] },
          { day: "Thursday", contentType: "seller_tips", description: "Home staging tips or pricing strategy advice for sellers", platforms: ["facebook", "linkedin"] },
          { day: "Saturday", contentType: "open_houses", description: "Open house announcement with date, time, address, and walkthrough teaser", platforms: ["instagram", "facebook", "x"] },
        ],
      };
      const effectiveBlueprint = blueprint || (businessType === 'real_estate' ? realEstateBlueprint : null);

      if (isTwoWeekMode && effectiveBlueprint) {
        const weekEntries = [...(effectiveBlueprint.week1 || []), ...(effectiveBlueprint.week2 || [])];
        for (let entryIdx = 0; entryIdx < weekEntries.length; entryIdx++) {
          const entry = weekEntries[entryIdx];
          const isWeek2 = entryIdx >= (effectiveBlueprint.week1?.length || 0);
          const weekBaseDay = isWeek2 ? effectiveStartDay + 7 : effectiveStartDay;
          const targetDayOffset = dayNameToOffset[entry.day] ?? 1;
          const baseDayOfWeek = new Date(year, month, weekBaseDay).getDay();
          let dayOfMonth = weekBaseDay + (targetDayOffset - baseDayOfWeek);
          if (dayOfMonth < weekBaseDay) dayOfMonth += 7;
          const weekEnd = weekBaseDay + 6;
          if (dayOfMonth > weekEnd) dayOfMonth -= 7;
          if (dayOfMonth < effectiveStartDay || dayOfMonth > fullMonthDays) continue;
          const neighborhood = neighborhoods[entryIdx % neighborhoods.length];
          const hour = postingHours[entryIdx % postingHours.length];

          for (let pi = 0; pi < entry.platforms.length; pi++) {
            const platform = entry.platforms[pi];
            const scheduleDate = new Date(year, month, dayOfMonth, hour, pi * 3, 0, 0);
            await generatePost(scheduleDate, entry.contentType, neighborhood, platform, entry.description);
          }
        }
      } else {
        const scheduleDates: Date[] = [];
        for (let week = 0; week < totalWeeks; week++) {
          const weekStart = week * 7;
          const availableDays: number[] = [];
          for (let d = weekStart; d < Math.min(weekStart + 7, daysInMonth); d++) {
            const dayNum = effectiveStartDay + d;
            if (dayNum <= fullMonthDays) {
              availableDays.push(dayNum);
            }
          }
          if (availableDays.length === 0) continue;
          const step = Math.max(1, Math.floor(availableDays.length / clampedPostsPerWeek));
          for (let p = 0; p < clampedPostsPerWeek && p < availableDays.length; p++) {
            const dayIndex = Math.min(p * step, availableDays.length - 1);
            const day = availableDays[dayIndex];
            const hour = postingHours[(week * clampedPostsPerWeek + p) % postingHours.length];
            const date = new Date(year, month, day, hour, 0, 0, 0);
            scheduleDates.push(date);
          }
        }

        for (let i = 0; i < scheduleDates.length; i++) {
          const scheduleDate = scheduleDates[i];
          const category = categories[i % categories.length];
          const neighborhood = neighborhoods[i % neighborhoods.length];
          for (let pi = 0; pi < platforms.length; pi++) {
            const platform = platforms[pi];
            const staggeredDate = new Date(scheduleDate.getTime());
            staggeredDate.setMinutes(staggeredDate.getMinutes() + pi * 3);
            await generatePost(staggeredDate, category, neighborhood, platform);
          }
        }
      }

      res.json({
        success: true,
        posts: generatedPosts,
        count: generatedPosts.length,
      });
    } catch (error) {
      console.error("Generate monthly content error:", error);
      res.status(500).json({ error: "Failed to generate monthly content" });
    }
  });

