  // Switch active WhatsApp account
  app.post("/api/whatsapp/accounts/switch", requireAuth, async (req, res) => {
    try {
      const userId = req.user?.id;
      if (!userId) return res.status(401).json({ error: "Authentication required" });

      const { phoneNumberId } = req.body;
      if (!phoneNumberId) {
        return res.status(400).json({ error: "Phone Number ID is required" });
      }

      const settings = await getWhatsappSettingsWithFallback(String(userId));
      const accounts = (settings?.accounts as Array<{ label: string; phoneNumberId: string; wabaId: string; displayPhoneNumber?: string; accessToken?: string }>) || [];
      const account = accounts.find(a => a.phoneNumberId === phoneNumberId);

      if (!account) {
        return res.status(404).json({ error: "Account not found" });
      }

      // Before switching, save the current main token to the departing account
      // so it's preserved for when we switch back
      if (settings?.phoneNumberId && settings?.accessToken && settings.accessToken.length >= 100) {
        const departingIdx = accounts.findIndex(a => a.phoneNumberId === settings.phoneNumberId);
        if (departingIdx >= 0) {
          const existingLen = (accounts[departingIdx].accessToken || "").length;
          if (!existingLen || existingLen < 100 || existingLen < settings.accessToken.length) {
            accounts[departingIdx].accessToken = settings.accessToken;
            console.log(`📱 WhatsApp: Saved main token to departing account "${accounts[departingIdx].label}" (len=${settings.accessToken.length})`);
          }
        }
      }

      const updates: any = {
        ...settings,
        userId: String(userId),
        phoneNumberId: account.phoneNumberId,
        wabaId: account.wabaId || settings?.wabaId || "",
        displayPhoneNumber: account.displayPhoneNumber || "",
        accounts,
      };

      if (account.accessToken) {
        updates.accessToken = account.accessToken;
        console.log(`📱 WhatsApp: Auto-switching to account token for "${account.label}"`);
      } else {
        console.log(`📱 WhatsApp: Account "${account.label}" has no per-account token — keeping main settings token`);
      }

      await storage.createOrUpdateWhatsappSettings(updates);

      console.log(`📱 WhatsApp: Switched to account "${account.label}" (${phoneNumberId}) for user ${userId}`);
      res.json({ success: true, activePhoneNumberId: phoneNumberId, label: account.label, hasOwnToken: !!account.accessToken });
    } catch (error: any) {
      console.error("Error switching WhatsApp account:", error);
      res.status(500).json({ error: "Failed to switch WhatsApp account" });
    }
  });

  // Save/update WhatsApp settings
  app.post("/api/whatsapp/settings", requireAuth, async (req, res) => {
    try {
      const userId = req.user?.id;
      if (!userId) return res.status(401).json({ error: "Authentication required" });

      const incoming = { ...req.body };
      const existing = await getWhatsappSettingsWithFallback(String(userId));

      if (!incoming.accessToken || incoming.accessToken.trim() === "") {
        if (existing?.accessToken) {
          incoming.accessToken = existing.accessToken;
        } else {
          delete incoming.accessToken;
        }
      }
      const existingAccounts = (existing?.accounts as Array<{ label: string; phoneNumberId: string; wabaId: string; displayPhoneNumber?: string; accessToken?: string }>) || [];
      const accounts = existingAccounts.map(a => ({ ...a }));

      if (incoming.phoneNumberId) {
        const idx = accounts.findIndex((a: any) => a.phoneNumberId === incoming.phoneNumberId);
        const entry: any = {
          label: incoming.displayPhoneNumber || incoming.phoneNumberId,
          phoneNumberId: incoming.phoneNumberId,
          wabaId: incoming.wabaId || existing?.wabaId || "",
          displayPhoneNumber: incoming.displayPhoneNumber || "",
        };
        if (incoming.accessToken && incoming.accessToken.trim()) {
          entry.accessToken = incoming.accessToken.trim();
        } else if (idx >= 0 && accounts[idx].accessToken) {
          entry.accessToken = accounts[idx].accessToken;
        }
        if (idx >= 0) {
          accounts[idx] = { ...accounts[idx], ...entry };
        } else {
          accounts.push(entry);
        }
      }
      incoming.accounts = accounts;

      const settings = await storage.createOrUpdateWhatsappSettings({
        ...incoming,
        userId: String(userId),
      });
      res.json(settings);
    } catch (error: any) {
      console.error("Error saving WhatsApp settings:", error);
      res.status(500).json({ error: "Failed to save WhatsApp settings" });
    }
  });

